import React,{ useState } from "react";
import {slideInLeft, slideInRight} from "react-animations";
import styled, { keyframes } from 'styled-components';
import axios from 'axios';
const Contact = () => {
    const SlideInLeft = styled.div`animation: 2s ${keyframes`${slideInLeft}`} infinite `;
    const SlideInRight = styled.div`animation: 2s ${keyframes`${slideInRight}`} infinite `;
    const [isNameChanged,onNameChange] = useState("");
    const [isEmailChanged,onEmailChange] = useState("");
    const [isMessageChanged,onMessageChange] = useState("");
    const [isMessageSent, onSendMessage] = useState([]);
    const sendMessage = () => {
        onSendMessage([
            ...isMessageSent, {
                name:isNameChanged,
                email:isEmailChanged,
                message:isMessageChanged
            }
        ])
    };
    const resetForm = () => {
        document.getElementById('contact-form').reset();
    };
    const handleSubmit = ( e ) => {
        e.preventDefault();

        axios({
            method: "POST",
            url:'API_URI',
            data:  isMessageSent
        }).then((response)=>{
            if (response.data.status === 'success'){
                alert("Message Sent.");
                resetForm();
            }else if(response.data.status === 'fail'){
                alert("Message failed to send.")
            }
        });


    };

    return(
        <div>
        <div className="ui center aligned segment">
            <h1 className="ui header" style={{fontWeight:"900"}} id="contact">
                <SlideInLeft style={{display:"inline-block"}}>
                    <i className="caret right icon" style={{textAlign:"left",fontSize:"1em"}}/>
                </SlideInLeft>
                Contact
                <SlideInRight style={{display:"inline-block"}}>
                    <i className="caret left icon" style={{textAlign:"right",fontSize:"1em"}}/>
                </SlideInRight>
            </h1>
        </div>
        <div className="ui segment">
            <form className="ui form" id="contact-form" method="POST" onSubmit={handleSubmit}>
                <div className="field">
                    <label htmlFor="name">Name</label>
                    <input type="text" className="form-control" placeholder="Full Name" onChange={onNameChange}/>
                </div>
                <div className="field">
                    <label htmlFor="email">Email address</label>
                    <input type="email" className="form-control" aria-describedby="emailHelp" placeholder="Email" onChange={onEmailChange}/>
                </div>
                <div className="field">
                    <label htmlFor="message">Message</label>
                    <textarea className="form-control" rows="5" onChange={onMessageChange}></textarea>
                </div>
                <button type="submit" className="ui inverted green button" onClick={()=>sendMessage}>Submit</button>
            </form>
        </div>
        </div>
    );
};
export default Contact;
